SELECT shipment_id
FROM shipments
WHERE customer_id = 1;

SELECT * 
FROM shipments
WHERE customer_id = 0 AND weight = (SELECT MAX(weight) FROM shipments WHERE customer_id = 0);

SELECT payment_method_name, supported_currencies
FROM payment_methods
WHERE payment_method_id = 1;

SELECT total_cost
FROM shipment_costs
WHERE shipment_id = 0;

SELECT current_status 
FROM tracking 
WHERE shipment_id = 0;

SELECT total_cost, currency_rate_at_calculation, cost_breakdown
FROM shipment_costs
WHERE shipment_id = 1;
